doc = Rhino.RhinoDoc.ActiveDoc
rows = []
for idef in doc.InstanceDefinitions:
    if idef is None:
        continue
    objs = idef.GetObjects()
    member_count = len(objs) if objs else 0
    rows.append({"name": idef.Name, "id": str(idef.Id), "member_count": member_count})
return {"definition_count": len(rows), "definitions": rows}
